Voici un exemple de hook utilisant useState, useEffect et AsyncStorage : 

```typescript
import { useState, useEffect } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useColorScheme } from 'react-native';

type ThemeMode = 'light' | 'dark' | 'system';

const THEME_KEY = 'app_theme_preference';

export const useThemePreference = () => {
  const systemScheme = useColorScheme(); // 'light' ou 'dark' du système
  const [themeMode, setThemeMode] = useState<ThemeMode>('system');
  const [effectiveTheme, setEffectiveTheme] = useState<'light' | 'dark'>('light');

  // Charger la préférence sauvegardée
  useEffect(() => {
    const loadTheme = async () => {
      const saved = await AsyncStorage.getItem(THEME_KEY);
      if (saved === 'light' || saved === 'dark' || saved === 'system') {
        setThemeMode(saved);
      }
    };
    loadTheme();
  }, []);

  // Calculer le thème effectif (light/dark) selon le mode choisi et le système
  useEffect(() => {
    let newEffective: 'light' | 'dark' = 'light';
    if (themeMode === 'system') {
      newEffective = systemScheme === 'dark' ? 'dark' : 'light';
    } else {
      newEffective = themeMode;
    }
    setEffectiveTheme(newEffective);
  }, [themeMode, systemScheme]);

  // Sauvegarder le mode quand il change
  const saveThemeMode = async (mode: ThemeMode) => {
    setThemeMode(mode);
    await AsyncStorage.setItem(THEME_KEY, mode);
  };

  return { themeMode, effectiveTheme, saveThemeMode };
};
```

```jsx
import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';
import { useThemePreference } from '../hooks/useThemePreference';

export const ThemeSwitch = () => {
  const { themeMode, saveThemeMode } = useThemePreference();

  const options = [
    { label: 'Clair', value: 'light' },
    { label: 'Sombre', value: 'dark' },
    { label: 'Auto', value: 'system' },
  ];

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Thème</Text>
      <View style={styles.optionsRow}>
        {options.map(opt => (
          <TouchableOpacity
            key={opt.value}
            style={[
              styles.option,
              themeMode === opt.value && styles.activeOption
            ]}
            onPress={() => saveThemeMode(opt.value as any)}
          >
            <Text style={themeMode === opt.value ? styles.activeText : styles.text}>
              {opt.label}
            </Text>
          </TouchableOpacity>
        ))}
      </View>
    </View>
  );
};

const styles = StyleSheet.create({ /* styles simplifiés */ });
```

```jsx
import React from 'react';
import { Provider as PaperProvider, DarkTheme as PaperDark, DefaultTheme as PaperDefault } from 'react-native-paper';
import { NavigationContainer, DarkTheme as NavigationDark, DefaultTheme as NavigationDefault } from '@react-navigation/native';
import { useThemePreference } from './hooks/useThemePreference';
import AppNavigator from './navigation/AppNavigator';

export default function App() {
  const { effectiveTheme } = useThemePreference();
  const isDark = effectiveTheme === 'dark';

  const paperTheme = isDark ? PaperDark : PaperDefault;
  const navTheme = isDark ? NavigationDark : NavigationDefault;

  return (
    <PaperProvider theme={paperTheme}>
      <NavigationContainer theme={navTheme}>
        <AppNavigator />
      </NavigationContainer>
    </PaperProvider>
  );
}
```

Cela garantit que tous les composants Paper et la navigation réagissent instantanément au changement de thème.

```typescript
import { useState, useEffect } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useColorScheme } from 'react-native';

export const useThemeFixed = () => {
  const [isDark, setIsDark] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const systemScheme = useColorScheme();

  // Charger la préférence au montage
  useEffect(() => {
    const loadTheme = async () => {
      try {
        const saved = await AsyncStorage.getItem('darkMode');
        if (saved !== null) {
          setIsDark(JSON.parse(saved));
        } else {
          // Option par défaut : suivre le système
          setIsDark(systemScheme === 'dark');
        }
      } catch (error) {
        console.error(error);
      } finally {
        setIsLoading(false);
      }
    };
    loadTheme();
  }, [systemScheme]);

  const toggleTheme = async () => {
    const newValue = !isDark;
    setIsDark(newValue);
    await AsyncStorage.setItem('darkMode', JSON.stringify(newValue));
  };

  return { isDark, isLoading, toggleTheme };
};
```

