import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { useTheme } from 'react-native-paper';

const PromoBanner = ({ customBackground, message }) => {
  const { colors, dark } = useTheme();
  const backgroundColor = customBackground || colors.surface;
  // Pour un bon contraste en mode sombre, s'assurer que le texte est clair
  const textColor = dark ? '#ffffff' : colors.text;

  return (
    <View style={[styles.banner, { backgroundColor }]}>
      <Text style={[styles.text, { color: textColor }]}>
        {message || 'Promotion spéciale ! -20% sur tout'}
      </Text>
    </View>
  );
};

const styles = StyleSheet.create({
  banner: { padding: 16, borderRadius: 8, margin: 8 },
  text: { fontWeight: 'bold', fontSize: 16 }
});

export default PromoBanner;
```

```jsx
import React from 'react';
import { View, Text } from 'react-native';
import { useTheme } from 'react-native-paper';

// Composant parent qui utilise le thème
const ProductList = ({ products }) => {
  const { colors } = useTheme();
  return (
    <View style={{ backgroundColor: colors.background }}>
      {products.map(p => (
        <MemoizedProductCard key={p.id} product={p} />
      ))}
    </View>
  );
};

// Composant enfant optimisé avec React.memo
const ProductCard = React.memo(({ product }) => {
  return (
    <View>
      <Text>{product.name}</Text>
    </View>
  );
});

const MemoizedProductCard = React.memo(ProductCard);
```
Ainsi, même si `ProductList` est re-rendu à cause du thème, `ProductCard` ne se re-rendra pas tant que ses props (ici `product`) n'ont pas changé.
